create extension if not exists pgcrypto;
create table schools(id uuid primary key default gen_random_uuid(),code text unique not null,name text not null,timezone text not null default 'Asia/Kolkata',is_active boolean not null default true,created_at timestamptz not null default now());
create table users(id uuid primary key default gen_random_uuid(),school_id uuid references schools(id),role text not null check(role in('super_admin','school_admin','driver','parent')),name text not null,email text not null,phone text,is_active boolean not null default true);
create table vehicles(id uuid primary key,school_id uuid not null references schools(id),code text not null,registration_no text not null,capacity integer,is_active boolean not null default true,unique(school_id,code));
create table routes(id uuid primary key,school_id uuid not null references schools(id),code text not null,name text not null,direction text not null check(direction in('morning','afternoon')),vehicle_id uuid not null references vehicles(id),driver_user_id uuid not null references users(id),is_active boolean not null default true,unique(school_id,code));
create table route_stops(id uuid primary key,school_id uuid not null references schools(id),route_id uuid not null references routes(id),name text not null,sequence_no integer not null,latitude numeric not null,longitude numeric not null);
create table students(id uuid primary key,school_id uuid not null references schools(id),admission_no text not null,name text not null,grade text not null,section text not null,avatar_url text,parent_user_id uuid not null references users(id),is_active boolean not null default true,unique(school_id,admission_no));
create table student_passes(id uuid primary key,school_id uuid not null references schools(id),student_id uuid not null references students(id),token_hash text not null,demo_token text,token_type text not null check(token_type in('qr','nfc')),status text not null check(status in('active','lost','replaced','inactive')),issued_at timestamptz not null default now(),expires_at timestamptz);
create table student_route_assignments(id uuid primary key,school_id uuid not null references schools(id),student_id uuid not null references students(id),route_id uuid not null references routes(id),stop_id uuid not null references route_stops(id),effective_from date not null,effective_to date,is_active boolean not null default true);
create table boarding_events(id uuid primary key default gen_random_uuid(),school_id uuid not null references schools(id),student_id uuid references students(id),student_pass_id uuid references student_passes(id),route_id uuid not null references routes(id),vehicle_id uuid not null references vehicles(id),driver_user_id uuid not null references users(id),service_date date not null,event_type text not null default 'boarding',status text not null,exception_type text,occurred_at timestamptz not null,received_at timestamptz not null default now(),latitude numeric,longitude numeric,accuracy_meters numeric,location_status text not null,location_failure_reason text,sync_source text not null,idempotency_key text not null,client_device_id text not null,client_clock_offset_ms integer,metadata jsonb not null default '{}',created_at timestamptz not null default now(),unique(school_id,idempotency_key));
create table parent_notifications(id uuid primary key default gen_random_uuid(),school_id uuid not null references schools(id),parent_user_id uuid not null references users(id),student_id uuid not null references students(id),boarding_event_id uuid not null references boarding_events(id),title text not null,body text not null,read_at timestamptz,created_at timestamptz not null default now());
create table demo_audit_events(id uuid primary key default gen_random_uuid(),school_id uuid references schools(id),event_type text not null,metadata jsonb not null default '{}',created_at timestamptz not null default now());
create index boarding_events_school_date on boarding_events(school_id,service_date,route_id);create index notifications_parent on parent_notifications(school_id,parent_user_id,created_at desc);
alter publication supabase_realtime add table boarding_events,parent_notifications;
